1	import { expect, test, type Page } from '@playwright/test';
2	
3	// ddx-7e7b12f0 — regression check that the doc-graph edges and arrow marker
4	// resolve to the fg-muted token in both themes (light #4B5563 / dark #B8AF9C),
5	// not the prior border-line token whose contrast against bg-canvas failed
6	// WCAG AA for non-text graphics.
7	
8	const NODE_INFO = { id: 'node-abc', name: 'Test Node' };
9	const PROJECT = { id: 'proj-1', name: 'Project Alpha', path: '/repos/alpha' };
10	
11	const GRAPH_URL = `/nodes/${NODE_INFO.id}/projects/${PROJECT.id}/graph`;
12	
13	const LIGHT_FG_MUTED = 'rgb(75, 85, 99)'; // #4B5563
14	const DARK_FG_MUTED = 'rgb(184, 175, 156)'; // #B8AF9C
15	
16	const DOC_GRAPH_FIXTURE = {
17		rootDir: '/repos/alpha',
18		documents: [
19			{
20				id: 'doc-a',
21				path: 'docs/a.md',
22				title: 'Doc A',
23				dependsOn: ['doc-b'],
24				dependents: []
25			},
26			{
27				id: 'doc-b',
28				path: 'docs/b.md',
29				title: 'Doc B',
30				dependsOn: [],
31				dependents: ['doc-a']
32			}
33		],
34		pathToId: JSON.stringify({ 'docs/a.md': 'doc-a', 'docs/b.md': 'doc-b' }),
35		warnings: [],
36		issues: []
37	};
38	
39	type GqlBody = { query: string; variables?: Record<string, unknown> };
40	
41	async function installGraphqlMocks(page: Page) {
42		await page.route('/graphql', async (route) => {
43			const body = route.request().postDataJSON() as GqlBody;
44			const q = body.query;
45	
46			if (q.includes('NodeInfo')) {
47				await route.fulfill({
48					status: 200,
49					contentType: 'application/json',
50					body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
51				});
52				return;
53			}
54			if (q.includes('Projects')) {
55				await route.fulfill({
56					status: 200,
57					contentType: 'application/json',
58					body: JSON.stringify({
59						data: { projects: { edges: [{ node: PROJECT }] } }
60					})
61				});
62				return;
63			}
64			if (q.includes('DocGraph') || q.includes('docGraph')) {
65				await route.fulfill({
66					status: 200,
67					contentType: 'application/json',
68					body: JSON.stringify({ data: { docGraph: DOC_GRAPH_FIXTURE } })
69				});
70				return;
71			}
72			if (q.includes('DocStale') || q.includes('docStale')) {
73				await route.fulfill({
74					status: 200,
75					contentType: 'application/json',
76					body: JSON.stringify({ data: { docStale: [] } })
77				});
78				return;
79			}
80			await route.continue();
81		});
82	}
83	
84	test('doc graph edges resolve to fg-muted token in light and dark themes', async ({ page }) => {
85		// Pre-load: clear any persisted dark theme so the light-theme assertion is
86		// deterministic regardless of the harness's previous browser state.
87		await page.addInitScript(() => {
88			document.documentElement.classList.remove('dark');
89		});
90	
91		await installGraphqlMocks(page);
92		await page.goto(GRAPH_URL);
93	
94		await expect(page.getByRole('heading', { name: 'Document Graph' })).toBeVisible();
95	
96		const svg = page.getByTestId('doc-graph-svg');
97		await expect(svg).toBeVisible();
98	
99		// AC2: at least one <line> SVG edge is rendered.
100		const edges = svg.locator('line');
101		await expect(edges.first()).toBeAttached();
102		expect(await edges.count()).toBeGreaterThanOrEqual(1);
103	
104		const arrowPath = svg.locator('defs marker#ddx-arrow path');
105		await expect(arrowPath).toBeAttached();
106	
107		// AC3: light-theme — both edge stroke and arrow marker fill resolve to
108		// rgb(75, 85, 99) (#4B5563 fg-muted).
109		await expect
110			.poll(async () => edges.first().evaluate((el) => getComputedStyle(el).stroke))
111			.toBe(LIGHT_FG_MUTED);
112		await expect
113			.poll(async () => arrowPath.evaluate((el) => getComputedStyle(el).fill))
114			.toBe(LIGHT_FG_MUTED);
115	
116		// AC4: toggle <html>.dark and re-assert against rgb(184, 175, 156)
117		// (#B8AF9C dark-fg-muted).
118		await page.evaluate(() => document.documentElement.classList.add('dark'));
119	
120		await expect
121			.poll(async () => edges.first().evaluate((el) => getComputedStyle(el).stroke))
122			.toBe(DARK_FG_MUTED);
123		await expect
124			.poll(async () => arrowPath.evaluate((el) => getComputedStyle(el).fill))
125			.toBe(DARK_FG_MUTED);
126	});
